#!/usr/bin/env bash

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
LOG_FILE="${LOG_FILE:-/tmp/aws-deploy-$(date +%Y%m%d-%H%M%S).log}"
DEPLOYMENT_TIMEOUT="${DEPLOYMENT_TIMEOUT:-600}"
AWS_REGION="${AWS_REGION:-us-east-1}"
ENVIRONMENT="${ENVIRONMENT:-development}"
DRY_RUN="${DRY_RUN:-false}"

log() {
    local level="$1"
    shift
    local message="$*"
    local timestamp=$(date '+%Y-%m-%d %H:%M:%S')
    echo "[${timestamp}] [${level}] ${message}" | tee -a "${LOG_FILE}"
}

error_exit() {
    log "ERROR" "$1"
    exit 1
}

check_dependencies() {
    local deps=("aws" "jq")
    for dep in "${deps[@]}"; do
        if ! command -v "${dep}" &> /dev/null; then
            error_exit "Required dependency '${dep}' not found. Please install it."
        fi
    done
}

setup_aws_credentials() {
    log "INFO" "Setting up AWS credentials..."
    
    if [[ -n "${AWS_ACCESS_KEY_ID:-}" && -n "${AWS_SECRET_ACCESS_KEY:-}" ]]; then
        log "INFO" "Using AWS credentials from environment variables"
        export AWS_ACCESS_KEY_ID="${AWS_ACCESS_KEY_ID}"
        export AWS_SECRET_ACCESS_KEY="${AWS_SECRET_ACCESS_KEY}"
        if [[ -n "${AWS_SESSION_TOKEN:-}" ]]; then
            export AWS_SESSION_TOKEN="${AWS_SESSION_TOKEN}"
        fi
    elif [[ -n "${AWS_PROFILE:-}" ]]; then
        log "INFO" "Using AWS profile: ${AWS_PROFILE}"
        export AWS_PROFILE="${AWS_PROFILE}"
    elif [[ -f "${HOME}/.aws/credentials" ]]; then
        log "INFO" "Using default AWS credentials from ~/.aws/credentials"
    else
        error_exit "No AWS credentials found. Set AWS_ACCESS_KEY_ID/AWS_SECRET_ACCESS_KEY or AWS_PROFILE"
    fi
    
    export AWS_DEFAULT_REGION="${AWS_REGION}"
    export AWS_REGION="${AWS_REGION}"
}

verify_aws_authentication() {
    log "INFO" "Verifying AWS authentication..."
    
    if ! aws sts get-caller-identity &> /dev/null; then
        error_exit "AWS authentication failed. Please check your credentials."
    fi
    
    local account_id=$(aws sts get-caller-identity --query Account --output text)
    local user_arn=$(aws sts get-caller-identity --query Arn --output text)
    
    log "INFO" "Successfully authenticated as: ${user_arn}"
    log "INFO" "AWS Account ID: ${account_id}"
    
    echo "${account_id}"
}

check_required_permissions() {
    log "INFO" "Checking required AWS permissions..."
    
    local required_actions=(
        "s3:ListBucket"
        "s3:PutObject"
        "cloudformation:DescribeStacks"
        "ec2:DescribeInstances"
    )
    
    local has_permissions=true
    
    for action in "${required_actions[@]}"; do
        if ! aws iam simulate-principal-policy \
            --policy-source-arn "$(aws sts get-caller-identity --query Arn --output text)" \
            --action-names "${action}" \
            --query 'EvaluationResults[0].EvalDecision' \
            --output text 2>/dev/null | grep -q "allowed"; then
            log "WARN" "May not have permission for: ${action}"
            has_permissions=false
        fi
    done
    
    if [[ "${has_permissions}" == "false" ]]; then
        log "WARN" "Some permissions may be missing. Deployment might fail."
    fi
}

create_s3_bucket_if_not_exists() {
    local bucket_name="$1"
    
    log "INFO" "Checking S3 bucket: ${bucket_name}"
    
    if aws s3 ls "s3://${bucket_name}" 2>&1 | grep -q 'NoSuchBucket'; then
        log "INFO" "Creating S3 bucket: ${bucket_name}"
        
        if [[ "${DRY_RUN}" == "true" ]]; then
            log "INFO" "[DRY-RUN] Would create bucket: ${bucket_name}"
            return 0
        fi
        
        if [[ "${AWS_REGION}" == "us-east-1" ]]; then
            aws s3 mb "s3://${bucket_name}" --region "${AWS_REGION}"
        else
            aws s3 mb "s3://${bucket_name}" --region "${AWS_REGION}" \
                --create-bucket-configuration LocationConstraint="${AWS_REGION}"
        fi
        
        aws s3api put-bucket-versioning \
            --bucket "${bucket_name}" \
            --versioning-configuration Status=Enabled
        
        aws s3api put-bucket-encryption \
            --bucket "${bucket_name}" \
            --server-side-encryption-configuration '{
                "Rules": [{
                    "ApplyServerSideEncryptionByDefault": {
                        "SSEAlgorithm": "AES256"
                    }
                }]
            }'
        
        log "INFO" "S3 bucket created successfully: ${bucket_name}"
    else
        log "INFO" "S3 bucket already exists: ${bucket_name}"
    fi
}

upload_to_s3() {
    local source_path="$1"
    local bucket_name="$2"
    local s3_key="$3"
    
    log "INFO" "Uploading ${source_path} to s3://${bucket_name}/${s3_key}"
    
    if [[ "${DRY_RUN}" == "true" ]]; then
        log "INFO" "[DRY-RUN] Would upload: ${source_path} to s3://${bucket_name}/${s3_key}"
        return 0
    fi
    
    if [[ ! -f "${source_path}" && ! -d "${source_path}" ]]; then
        error_exit "Source path does not exist: ${source_path}"
    fi
    
    if [[ -d "${source_path}" ]]; then
        aws s3 sync "${source_path}" "s3://${bucket_name}/${s3_key}" \
            --delete \
            --exact-timestamps
    else
        aws s3 cp "${source_path}" "s3://${bucket_name}/${s3_key}" \
            --metadata "deployment-time=$(date -u +%Y-%m-%dT%H:%M:%SZ),environment=${ENVIRONMENT}"
    fi
    
    log "INFO" "Upload completed successfully"
}

deploy_cloudformation_stack() {
    local stack_name="$1"
    local template_file="$2"
    local parameters_file="${3:-}"
    
    log "INFO" "Deploying CloudFormation stack: ${stack_name}"
    
    if [[ ! -f "${template_file}" ]]; then
        error_exit "Template file not found: ${template_file}"
    fi
    
    local deploy_cmd="aws cloudformation deploy \
        --template-file ${template_file} \
        --stack-name ${stack_name} \
        --region ${AWS_REGION} \
        --capabilities CAPABILITY_IAM CAPABILITY_NAMED_IAM \
        --no-fail-on-empty-changeset"
    
    if [[ -n "${parameters_file}" && -f "${parameters_file}" ]]; then
        deploy_cmd="${deploy_cmd} --parameter-overrides file://${parameters_file}"
    fi
    
    deploy_cmd="${deploy_cmd} --tags Environment=${ENVIRONMENT} DeployedBy=aws-deploy-script DeploymentTime=$(date -u +%Y-%m-%dT%H:%M:%SZ)"
    
    if [[ "${DRY_RUN}" == "true" ]]; then
        log "INFO" "[DRY-RUN] Would execute: ${deploy_cmd}"
        return 0
    fi
    
    if eval "${deploy_cmd}"; then
        log "INFO" "CloudFormation stack deployed successfully: ${stack_name}"
        wait_for_stack_complete "${stack_name}"
    else
        error_exit "CloudFormation deployment failed for stack: ${stack_name}"
    fi
}

wait_for_stack_complete() {
    local stack_name="$1"
    local timeout="${DEPLOYMENT_TIMEOUT}"
    local elapsed=0
    local interval=10
    
    log "INFO" "Waiting for stack to complete: ${stack_name}"
    
    while [[ ${elapsed} -lt ${timeout} ]]; do
        local stack_status=$(aws cloudformation describe-stacks \
            --stack-name "${stack_name}" \
            --region "${AWS_REGION}" \
            --query 'Stacks[0].StackStatus' \
            --output text 2>/dev/null || echo "UNKNOWN")
        
        case "${stack_status}" in
            CREATE_COMPLETE|UPDATE_COMPLETE)
                log "INFO" "Stack operation completed successfully: ${stack_status}"
                return 0
                ;;
            CREATE_FAILED|ROLLBACK_COMPLETE|ROLLBACK_FAILED|UPDATE_ROLLBACK_COMPLETE|UPDATE_ROLLBACK_FAILED|DELETE_FAILED)
                error_exit "Stack operation failed with status: ${stack_status}"
                ;;
            *IN_PROGRESS)
                log "INFO" "Stack status: ${stack_status} (${elapsed}s elapsed)"
                ;;
        esac
        
        sleep ${interval}
        elapsed=$((elapsed + interval))
    done
    
    error_exit "Stack operation timed out after ${timeout} seconds"
}

deploy_lambda_function() {
    local function_name="$1"
    local zip_file="$2"
    local runtime="${3:-python3.9}"
    local handler="${4:-lambda_function.lambda_handler}"
    local role_arn="$5"
    
    log "INFO" "Deploying Lambda function: ${function_name}"
    
    if [[ ! -f "${zip_file}" ]]; then
        error_exit "Lambda deployment package not found: ${zip_file}"
    fi
    
    if [[ "${DRY_RUN}" == "true" ]]; then
        log "INFO" "[DRY-RUN] Would deploy Lambda function: ${function_name}"
        return 0
    fi
    
    if aws lambda get-function --function-name "${function_name}" --region "${AWS_REGION}" &> /dev/null; then
        log "INFO" "Updating existing Lambda function: ${function_name}"
        aws lambda update-function-code \
            --function-name "${function_name}" \
            --zip-file "fileb://${zip_file}" \
            --region "${AWS_REGION}" \
            --publish
    else
        log "INFO" "Creating new Lambda function: ${function_name}"
        aws lambda create-function \
            --function-name "${function_name}" \
            --runtime "${runtime}" \
            --handler "${handler}" \
            --role "${role_arn}" \
            --zip-file "fileb://${zip_file}" \
            --region "${AWS_REGION}" \
            --timeout 30 \
            --memory-size 256 \
            --environment "Variables={ENVIRONMENT=${ENVIRONMENT}}" \
            --tags "Environment=${ENVIRONMENT},DeployedBy=aws-deploy-script"
    fi
    
    log "INFO" "Lambda function deployed successfully: ${function_name}"
}

update_ecs_service() {
    local cluster_name="$1"
    local service_name="$2"
    local task_definition="$3"
    
    log "INFO" "Updating ECS service: ${service_name} in cluster: ${cluster_name}"
    
    if [[ "${DRY_RUN}" == "true" ]]; then
        log "INFO" "[DRY-RUN] Would update ECS service: ${service_name}"
        return 0
    fi
    
    aws ecs update-service \
        --cluster "${cluster_name}" \
        --service "${service_name}" \
        --task-definition "${task_definition}" \
        --force-new-deployment \
        --region "${AWS_REGION}"
    
    log "INFO" "Waiting for ECS service to stabilize..."
    
    aws ecs wait services-stable \
        --cluster "${cluster_name}" \
        --services "${service_name}" \
        --region "${AWS_REGION}"
    
    log "INFO" "ECS service updated successfully: ${service_name}"
}

invalidate_cloudfront_distribution() {
    local distribution_id="$1"
    local paths="${2:-/*}"
    
    log "INFO" "Creating CloudFront invalidation for distribution: ${distribution_id}"
    
    if [[ "${DRY_RUN}" == "true" ]]; then
        log "INFO" "[DRY-RUN] Would invalidate CloudFront paths: ${paths}"
        return 0
    fi
    
    local invalidation_id=$(aws cloudfront create-invalidation \
        --distribution-id "${distribution_id}" \
        --paths ${paths} \
        --query 'Invalidation.Id' \
        --output text)
    
    log "INFO" "CloudFront invalidation created: ${invalidation_id}"
    
    log "INFO" "Waiting for invalidation to complete..."
    aws cloudfront wait invalidation-completed \
        --distribution-id "${distribution_id}" \
        --id "${invalidation_id}"
    
    log "INFO" "CloudFront invalidation completed successfully"
}

rollback_deployment() {
    local stack_name="$1"
    
    log "WARN" "Initiating rollback for stack: ${stack_name}"
    
    if [[ "${DRY_RUN}" == "true" ]]; then
        log "INFO" "[DRY-RUN] Would rollback stack: ${stack_name}"
        return 0
    fi
    
    aws cloudformation cancel-update-stack \
        --stack-name "${stack_name}" \
        --region "${AWS_REGION}" 2>/dev/null || true
    
    log "INFO" "Rollback initiated for stack: ${stack_name}"
}

cleanup_old_versions() {
    local bucket_name="$1"
    local prefix="$2"
    local keep_versions="${3:-5}"
    
    log "INFO" "Cleaning up old versions in s3://${bucket_name}/${prefix}"
    
    if [[ "${DRY_RUN}" == "true" ]]; then
        log "INFO" "[DRY-RUN] Would cleanup old versions (keep ${keep_versions})"
        return 0
    fi
    
    aws s3api list-object-versions \
        --bucket "${bucket_name}" \
        --prefix "${prefix}" \
        --query "Versions[?IsLatest==\`false\`]|sort_by(@, &LastModified)|[:-${keep_versions}].[Key,VersionId]" \
        --output text | while read -r key version_id; do
        if [[ -n "${key}" && -n "${version_id}" ]]; then
            log "INFO" "Deleting old version: ${key} (${version_id})"
            aws s3api delete-object \
                --bucket "${bucket_name}" \
                --key "${key}" \
                --version-id "${version_id}"
        fi
    done
    
    log "INFO" "Cleanup completed"
}

